mapper.select:
SELECT stat_date AS statDate, project_id AS projectId, building_id AS buildingId, floor_id AS floorId, format_type AS formatType, total_shops, rented_shops, vacant_shops, decorating_shops, opened_shops, total_area, rented_area, vacant_area, decoration_area, vacancy_rate, rental_rate, opening_rate FROM rpt_asset_daily WHERE is_deleted = 0 AND stat_date = #{statDate} AND project_id = #{projectId} AND building_id = #{buildingId} AND floor_id = #{floorId} AND format_type = #{formatType}
AND NOT (building_id = 0 AND floor_id = 0 AND format_type = '')
ORDER BY project_id, building_id, floor_id, format_type

SELECT p.province AS province, p.city AS city, COUNT(DISTINCT a.project_id) AS projectCount, SUM(a.total_shops) AS totalShops, SUM(a.rented_shops) AS rentedShops, SUM(a.vacant_shops) AS vacantShops, SUM(a.total_area) AS totalArea, SUM(a.rented_area) AS rentedArea, SUM(a.vacant_area) AS vacantArea, CASE WHEN SUM(a.total_area) > 0 THEN ROUND(SUM(a.rented_area) / SUM(a.total_area) * 100, 2) ELSE 0 END AS rentalRate, CASE WHEN SUM(a.total_area) > 0 THEN ROUND(SUM(a.vacant_area) / SUM(a.total_area) * 100, 2) ELSE 0 END AS vacancyRate FROM rpt_asset_daily a INNER JOIN biz_project p ON a.project_id = p.id AND p.is_deleted = 0 WHERE a.is_deleted = 0 AND a.stat_date = #{statDate} AND a.building_id = 0 AND a.floor_id = 0 AND a.format_type = ''
AND a.project_id IN #{id}
GROUP BY p.province, p.city ORDER BY SUM(a.total_area) DESC

SELECT project_id AS projectId, building_id AS buildingId, floor_id AS floorId, format_type AS formatType, rented_shops AS merchantCount, total_shops AS totalShops, rental_rate AS rentalRate, rented_area AS rentedArea, total_area AS totalArea FROM rpt_asset_daily WHERE is_deleted = 0 AND stat_date = #{statDate} AND floor_id != 0 /* 只取楼层粒度及以下（排除项目级/楼栋级汇总行）*/ AND project_id = #{projectId} AND building_id = #{buildingId}
AND project_id IN #{id}
ORDER BY project_id, building_id, floor_id, format_type

SELECT s.id AS shopId, s.shop_code AS shopCode, s.project_id AS projectId, s.building_id AS buildingId, s.floor_id AS floorId, CASE WHEN s.parent_shop_id IS NOT NULL THEN 'SPLIT' WHEN EXISTS ( SELECT 1 FROM biz_shop c WHERE c.parent_shop_id = s.id AND c.is_deleted = 0 ) THEN 'MERGE' ELSE 'ORIGINAL' END AS operationType, DATE(s.created_at) AS operationDate, s.parent_shop_id AS parentShopId, ps.shop_code AS parentShopCode, s.rent_area AS rentArea, s.actual_area AS actualArea, s.shop_status AS shopStatus, s.plan_format AS planFormat FROM biz_shop s LEFT JOIN biz_shop ps ON s.parent_shop_id = ps.id AND ps.is_deleted = 0 WHERE s.is_deleted = 0 AND s.project_id = #{projectId} AND s.building_id = #{buildingId}
AND s.project_id IN #{id}
ORDER BY s.project_id, s.building_id, s.floor_id, s.shop_code LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM biz_shop s
WHERE s.is_deleted = 0
AND s.project_id = #{projectId}
AND s.building_id = #{buildingId}

    AND s.project_id IN
    #{id}
